var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"흠… 그래도 침식체를 잡았는데, 벌이가 없는 건 너무 아쉬워….","JPN":"ふーん……でもやっぱり、侵食体を倒したのに何の収穫もないのは残念だね……","ENG":"Hmm... But it is a shame that we got nothing after defeating all those C.O.s...","TWN":"嗯……雖然打敗了侵蝕體，但沒有報酬真是太遺憾了……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아참! 오늘은 우리가 만난 기념으로 뭐라도 먹지 않을래?","JPN":"そうだ！　私たちの出会いを記念して何か食べに行かない？","ENG":"Oh, right! Why don't we eat something together to commemorate today?","TWN":"對了！今天是我們相遇的日子，要不要吃點什麼紀念一下？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"기념이라고?","JPN":"記念？","ENG":"Commemorate?","TWN":"紀念一下？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"사실 내가 맛있는 걸 먹고 싶을 뿐이지만. 헤헤.","JPN":"実はそれを口実においしいものが食べたいだけなんだけど……へへっ。","ENG":"Actually, I just want to eat something tasty. Hehe.","TWN":"其實我只是想吃好吃的而已。嘿嘿。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아차, 마브카는 음식을….","JPN":"あっ、そういえばマブカは食べ物が……","ENG":"That's right. Mavka doesn't eat–","TWN":"啊，瑪卡不能吃東西……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"괜찮아. 나 때문에 평생 굶을 거야?","JPN":"大丈夫。私といる間、何も食べないでいるつもり？","ENG":"It's fine. Are you going to starve because of me?","TWN":"沒關係。難道你要因為我一輩子餓肚子嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"눈치보지 말고 하고 싶은 대로 해.","JPN":"私のことは気にしないで、好きにして。","ENG":"If there's something you want to do, just do it.","TWN":"別顧慮我，想做什麼就做什麼。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헷.","JPN":"へへっ。","ENG":"Hehe.","TWN":"嘿嘿。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"줄이 굉장히 기네. 평소에도 하루 종일 기다려야 해?","JPN":"列が長いね。いつもこんな感じなの？","ENG":"So many people waiting in line here. Do you normally have to wait this long?","TWN":"隊伍真長，平時也要等一整天嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응. 이터니움 좀 받았다고 괜히 호들갑을 떤 게 아니라니까?","JPN":"うん。エタニウムもらって騒いでたのにはそれなりの理由があるんだよ。","ENG":"Yeah. Things are always insufficient, which is why I was excited about getting some Eternium.","TWN":"嗯……只是因為今天大家都拿到了一些永恆之金。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"오늘 들러야 할 곳은 빵집하고, 식료품점하고, 약국, 그리고 음….","JPN":"今日はね、パン屋と食料品店と、薬局と……うーんとね……","ENG":"Today, we need to stop by the bakery, the grocery store, the pharmacy, and...","TWN":"今天要去的地方有麵包店、雜貨店、藥店，還有……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아참, 식료품은 저번에 배급받은게 있으니까 괜찮으려나?","JPN":"あ、食料品はこの前配給してもらったやつが残ってるからまだいいかな。","ENG":"Oh! Maybe we don't need to go to the grocery store because I still have some food rations I got last time.","TWN":"對了，上次領到的配給食物應該還夠用吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아이 추워! 일단 빵집부터 가자. 뭐라도 남아있는게 있다면 좋을텐데….","JPN":"うう～寒！　とりあえずパン屋から行こう。まだ買えるものがあるといいんだけど……","ENG":"Brr! It's so cold! Let's head to the bakery first. It would be nice if there were some bread left...","TWN":"哎呀，好冷！先去麵包店吧。希望還有剩下的……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"사샤구나. 옆에 아이는 분명…","JPN":"サシャ、来たんだね。隣の子は確か……","ENG":"It's you, Sasha. And the child next to you must be–","TWN":"是莎夏啊。旁邊的孩子是……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이 아이는 마브카. 제 친구예요!","JPN":"この子はマブカ。私の友だちです！","ENG":"She's Mavka! My friend!","TWN":"這是瑪卡。是我的朋友！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"그렇구나… 어디서 왔니?","JPN":"あらそう……どこから来たの？","ENG":"I see... Where is she from?","TWN":"原來如此……你從哪裡來的？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"앗 그, 그러니까… 이 애는 몸이 불편한 애인데, 제가 어떻게든 치료해줬….","JPN":"あっ、そ、その……この子は体がちょっと不自由だから、私が直して……","ENG":"Oh, um... She's a little unwell, so I fixed her up–","TWN":"呃，這個……她身體不好，我好不容易才治……治……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난 북방군 소속이었어. 하지만 지금은 아냐.","JPN":"私は北方軍の所属だった。でも今は違う。","ENG":"I was a part of the Northern Army. But not anymore.","TWN":"我曾經是北方軍的一員。但現在不是了。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"북방군….","JPN":"北方軍……","ENG":"The Northern Army...","TWN":"北方軍……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"앗! 그, 그러니까….","JPN":"あっ！　こ、これはね……！","ENG":"Oh! U-um...","TWN":"哎呀！這，這個……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"그래. 딱하기도 하지.","JPN":"そうなのね。可哀想に……","ENG":"Oh, you poor thing.","TWN":"是啊。真是怪可憐的。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"네, 네?!","JPN":"え、えっ！？","ENG":"H-huh?!","TWN":"啊？什麼？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아줌마는 날 경계하지 않는 거야?","JPN":"おばさんは私を警戒しないの？","ENG":"Aren't you cautious about me?","TWN":"你不提防我嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"경계하다니? 우리 마을을 구해준 사람을 경계하는 바보가 있을까?","JPN":"警戒？　この村を救ってくれた人を警戒するなんてあり得ないでしょう。","ENG":"Cautious? I'd be foolish to be cautious about someone who just saved our village.","TWN":"提防？有誰會提防救了我們村子的人呢？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"침식경보가 울리고 너희 둘이 민병단들이 있는 곳으로 향하는 걸 봤단다.","JPN":"侵食警報が鳴った時、あなたたち二人が民兵団のところへ行くのを見たの。","ENG":"I saw you two head to where the militia were as soon as the Corruption alert went off.","TWN":"侵蝕警報響起來的時候，我看到你們兩個朝民兵團的方向去了。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"너희들은 마을을 위해 싸워줬는데, 오히려 보답해야지.","JPN":"あなたたちは村のために戦ってくれた。むしろお礼をしないとね。","ENG":"You fought for the village. I should be thanking you.","TWN":"你們為村子而戰，當然要報答你們才對。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};